import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, Info, Plus, Search, MessageCircle, HelpCircle, LayoutDashboard, Users, Folder, HardDrive, File
} from 'lucide-react';

const Login = () => {
  // --- STATE ---
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [showSupport, setShowSupport] = useState(false); 
  const [showFileSystem, setShowFileSystem] = useState(false); // NEW: Controls the Left-Side File Explorer
  const [userRequests, setUserRequests] = useState([]); 
  const [selectedFile, setSelectedFile] = useState(""); // Stores the chosen file name

  // --- PERSISTENCE ---
  useEffect(() => {
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('userRole');
    if (token) {
      setIsLoggedIn(true);
      if (role === 'admin') setView('admin-dashboard');
      else setView('dashboard');
    }
  }, []);

  // --- AUTH LOGIC ---
  const handleAuth = async (e) => {
    e.preventDefault();
    const mode = view === 'register' ? 'register' : 'login';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      if (mode === 'login') {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userRole', res.data.user.role);
        localStorage.setItem('userId', res.data.user._id);
        localStorage.setItem('userName', res.data.user.name);
        setIsLoggedIn(true);
        if (res.data.user.role === 'admin') setView('admin-dashboard');
        else setView('dashboard');
      } else { setView('login'); }
    } catch (err) { alert("Auth Failed"); }
  };

  // --- SUBMISSION ---
  const handleCredentialSubmit = async (e) => {
    e.preventDefault();
    const requestBody = {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
      documentUrl: selectedFile || "not_uploaded.pdf"
    };
    try {
      const res = await axios.post('http://localhost:5000/api/requests/submit', requestBody);
      setUserRequests([res.data.request, ...userRequests]);
      setShowModal(false);
      setSelectedFile("");
      alert("✅ Submitted Successfully!");
      setActiveTab('tracking'); 
    } catch (err) { alert("Error"); }
  };

  // ==========================================
  // NEW: LEFT-SIDE SYSTEM FILE EXPLORER COMPONENT
  // ==========================================
  const FileSystemExplorer = () => (
    <div className={`fixed inset-y-0 left-0 w-80 bg-slate-900 shadow-2xl z-[300] transform transition-transform duration-500 ${showFileSystem ? 'translate-x-0' : '-translate-x-full'} flex flex-col`}>
      <div className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-950">
        <h3 className="text-blue-400 font-black flex items-center gap-2 uppercase text-xs tracking-tighter"><HardDrive size={16}/> System Explorer</h3>
        <button onClick={() => setShowFileSystem(false)} className="text-slate-500 hover:text-white"><X size={20}/></button>
      </div>
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {/* Drives */}
        <div className="space-y-1">
          <p className="text-[10px] font-black text-slate-600 uppercase ml-2 mb-2">Devices & Drives</p>
          <div className="flex items-center gap-3 p-3 bg-slate-800/40 rounded-xl text-slate-300 hover:bg-slate-800 transition cursor-pointer"><HardDrive size={16}/> <span className="text-sm font-bold">Local Disk (C:)</span></div>
          <div className="flex items-center gap-3 p-3 text-slate-500 hover:bg-slate-800 rounded-xl transition cursor-pointer"><HardDrive size={16}/> <span className="text-sm font-bold">Recovery (D:)</span></div>
        </div>
        {/* Folders */}
        <div className="space-y-1 mt-6">
          <p className="text-[10px] font-black text-slate-600 uppercase ml-2 mb-2">Frequent Folders</p>
          {['Documents', 'Downloads', 'Desktop', 'Pictures'].map(folder => (
            <div key={folder} className="flex items-center gap-3 p-3 text-slate-400 hover:bg-slate-800 rounded-xl transition cursor-pointer font-bold text-sm"><Folder size={16} className="text-blue-500"/> {folder}</div>
          ))}
        </div>
        {/* Simulated Files to select */}
        <div className="space-y-1 mt-6">
          <p className="text-[10px] font-black text-slate-600 uppercase ml-2 mb-2">Recent Files</p>
          {['Medical_License.pdf', 'ID_Card_Front.jpg', 'DEA_Cert_2024.png'].map(file => (
            <div 
              key={file} 
              onClick={() => { setSelectedFile(file); setShowFileSystem(false); }}
              className="flex items-center gap-3 p-3 bg-blue-600/10 border border-blue-500/20 text-blue-400 hover:bg-blue-600 hover:text-white rounded-xl transition cursor-pointer font-bold text-xs"
            >
              <File size={16}/> {file}
            </div>
          ))}
        </div>
      </div>
      <div className="p-4 bg-slate-950 text-[10px] text-slate-600 text-center italic">Secure File Access Enabled</div>
    </div>
  );

  // Landing, Login, Admin views remain same... (Omitted for brevity, keep your current logic)
  if (view === 'landing') return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 relative">
      <div className="text-center mb-12">
        <div className="inline-block bg-blue-600 p-4 rounded-3xl mb-4 text-white shadow-xl shadow-blue-200"><ShieldCheck size={48} /></div>
        <h1 className="text-5xl font-black text-slate-900 tracking-tight italic uppercase">QUAD SOLUTIONS</h1>
        <p className="text-slate-500 font-medium italic">Credentialing Management</p>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl w-full">
        <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition">
          <UserPlus className="text-blue-600 mb-6" size={32} />
          <h2 className="text-2xl font-black mb-2">New Providers</h2>
          <div className="text-blue-600 font-bold">Get Started <ArrowRight size={20} className="inline ml-2" /></div>
        </div>
        <div onClick={() => setView('login')} className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition">
          <LogIn className="text-blue-400 mb-6" size={32} />
          <h2 className="text-2xl font-black mb-2">Existing Clients</h2>
          <div className="text-blue-400 font-bold">Sign In <ArrowRight size={20} className="inline ml-2" /></div>
        </div>
      </div>
    </div>
  );

  if (view === 'login' || view === 'register') return (
    <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6">
      <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
        <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 hover:text-slate-600 font-bold">Back</button>
        <h2 className="text-4xl font-black mb-8 text-slate-900">{view === 'login' ? 'Login' : 'Register'}</h2>
        <form onSubmit={handleAuth} className="space-y-4">
          {view === 'register' && <input type="text" placeholder="Name" className="w-full p-4 bg-slate-50 rounded-2xl outline-none" onChange={e => setFormData({...formData, name: e.target.value})} />}
          <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 rounded-2xl outline-none" onChange={e => setFormData({...formData, email: e.target.value})} />
          <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl outline-none" onChange={e => setFormData({...formData, password: e.target.value})} />
          <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black">Continue</button>
        </form>
      </div>
    </div>
  );

  // --- MAIN DASHBOARD RENDER ---
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col relative overflow-hidden">
      
      {/* 1. ATTACH THE FILE SYSTEM EXPLORER HERE */}
      <FileSystemExplorer />

      <nav className="bg-white shadow-sm p-4 sticky top-0 z-50 border-b">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
          <div className="flex gap-4 items-center">
             <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>Services</button>
             <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>My Status</button>
             <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold"><LogOut size={20}/></button>
          </div>
        </div>
      </nav>

      <main className="p-10 max-w-5xl mx-auto w-full">
        {activeTab === 'services' ? (
          <section>
             <h2 className="text-3xl font-black text-slate-900 mb-8">Service Catalog</h2>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map((title, idx) => (
                  <div key={idx} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                    <div className="w-12 h-12 bg-blue-50 rounded-xl flex items-center justify-center mb-4 text-blue-600"><FileText/></div>
                    <h3 className="text-xl font-bold mb-4">{title}</h3>
                    <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold hover:bg-blue-600 transition">Apply Now</button>
                  </div>
                ))}
             </div>
          </section>
        ) : (
          <section>
             <h2 className="text-3xl font-black text-slate-900 mb-8">Tracking History</h2>
             {userRequests.map((req, idx) => (
               <div key={req._id} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex justify-between items-center mb-4">
                 <div className="font-bold">{req.type}</div>
                 <div className="bg-blue-100 text-blue-600 px-3 py-1 rounded-lg text-xs font-black uppercase">{req.status}</div>
               </div>
             ))}
          </section>
        )}
      </main>

      {/* --- SUBMISSION MODAL --- */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10">
            <h2 className="text-2xl font-black mb-6 text-blue-600">New Submission</h2>
            <form onSubmit={handleCredentialSubmit} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-2xl border-none font-bold text-slate-700 outline-none"><option>Medical License</option><option>Insurance Enrollment</option><option>DEA Certification</option></select>
              <input type="text" placeholder="License ID" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" required />
              
              {/* --- CLICKING THIS BOX TRIGGERS THE LEFT SIDEBAR --- */}
              <div 
                onClick={() => setShowFileSystem(true)} 
                className="mt-1 p-8 bg-blue-50 rounded-2xl border-2 border-dashed border-blue-200 text-center cursor-pointer hover:bg-blue-100 transition"
              >
                <Upload className="mx-auto text-blue-400 mb-2" size={28}/>
                <p className="text-[10px] font-black text-blue-600 uppercase">
                  {selectedFile ? `READY: ${selectedFile}` : "Browse System Files"}
                </p>
                <p className="text-[10px] text-slate-400 mt-1 italic italic">Opens System Dialog on Left</p>
              </div>

              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black mt-4 shadow-xl">Confirm Submission</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full text-slate-400 font-bold text-sm">Cancel</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
